import React, { useState, useEffect } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";

export default function ClientesPage() {
  const [clientes, setClientes] = useState([]);
  const [nuevoCliente, setNuevoCliente] = useState({
    nombre: "",
    correo: "",
    telefono: "",
  });
  const [editando, setEditando] = useState(null);

  // 🔹 Cargar lista de clientes al iniciar
  useEffect(() => {
    obtenerClientes();
  }, []);

  const obtenerClientes = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/clientes");
      setClientes(res.data);
    } catch (err) {
      console.error("Error al obtener clientes:", err);
    }
  };

  const manejarCambio = (e) => {
    setNuevoCliente({ ...nuevoCliente, [e.target.name]: e.target.value });
  };

  const guardarCliente = async (e) => {
    e.preventDefault();
    try {
      if (editando) {
        // 🟡 Actualizar cliente existente
        await axios.put(`http://localhost:5000/api/clientes/${editando}`, nuevoCliente);
      } else {
        // 🟢 Crear nuevo cliente
        await axios.post("http://localhost:5000/api/clientes", nuevoCliente);
      }
      setNuevoCliente({ nombre: "", correo: "", telefono: "" });
      setEditando(null);
      obtenerClientes();
    } catch (err) {
      console.error("Error al guardar cliente:", err);
    }
  };

  const editarCliente = (cliente) => {
    setNuevoCliente(cliente);
    setEditando(cliente.id);
  };

  const eliminarCliente = async (id) => {
    if (!window.confirm("¿Seguro que deseas eliminar este cliente?")) return;
    try {
      await axios.delete(`http://localhost:5000/api/clientes/${id}`);
      obtenerClientes();
    } catch (err) {
      console.error("Error al eliminar cliente:", err);
    }
  };

  return (
    <div className="container mt-4">
      <h2 className="text-center mb-4">👥 Administración de Clientes</h2>

      {/* 🧾 Formulario de creación/edición */}
      <form onSubmit={guardarCliente} className="mb-4">
        <div className="row g-3">
          <div className="col-md-4">
            <input
              type="text"
              name="nombre"
              className="form-control"
              placeholder="Nombre"
              value={nuevoCliente.nombre}
              onChange={manejarCambio}
              required
            />
          </div>
          <div className="col-md-4">
            <input
              type="email"
              name="correo"
              className="form-control"
              placeholder="Correo"
              value={nuevoCliente.correo}
              onChange={manejarCambio}
              required
            />
          </div>
          <div className="col-md-3">
            <input
              type="text"
              name="telefono"
              className="form-control"
              placeholder="Teléfono"
              value={nuevoCliente.telefono}
              onChange={manejarCambio}
            />
          </div>
          <div className="col-md-1 d-grid">
            <button type="submit" className="btn btn-success">
              {editando ? "💾 Actualizar" : "➕ Agregar"}
            </button>
          </div>
        </div>
      </form>

      {/* 📋 Tabla de clientes */}
      <table className="table table-bordered table-striped">
        <thead className="table-dark">
          <tr>
            <th>ID</th>
            <th>Nombre</th>
            <th>Correo</th>
            <th>Teléfono</th>
            <th>Acciones</th>
          </tr>
        </thead>
        <tbody>
          {clientes.length > 0 ? (
            clientes.map((cliente) => (
              <tr key={cliente.id}>
                <td>{cliente.id}</td>
                <td>{cliente.nombre}</td>
                <td>{cliente.correo}</td>
                <td>{cliente.telefono || "—"}</td>
                <td>
                  <button
                    onClick={() => editarCliente(cliente)}
                    className="btn btn-warning btn-sm me-2"
                  >
                    ✏️ Editar
                  </button>
                  <button
                    onClick={() => eliminarCliente(cliente.id)}
                    className="btn btn-danger btn-sm"
                  >
                    🗑️ Eliminar
                  </button>
                </td>
              </tr>
            ))
          ) : (
            <tr>
              <td colSpan="5" className="text-center">
                No hay clientes registrados.
              </td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
}
